import React, { useState } from 'react';
import { View, Image, TouchableOpacity, Alert, ActivityIndicator } from 'react-native';
import * as ImagePicker from 'expo-image-picker';
import { Button, Text } from 'react-native-paper';

const AvatarPicker = ({ initialAvatar, onUpload }) => {
  const [avatarUri, setAvatarUri] = useState(initialAvatar || null);
  const [uploading, setUploading] = useState(false);

  const requestPermissions = async (type) => {
    if (type === 'camera') {
      const { status } = await ImagePicker.requestCameraPermissionsAsync();
      if (status !== 'granted') {
        Alert.alert('Erreur', 'Permission caméra refusée');
        return false;
      }
    } else {
      const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();
      if (status !== 'granted') {
        Alert.alert('Erreur', 'Permission galerie refusée');
        return false;
      }
    }
    return true;
  };

  const pickImage = async (useCamera) => {
    const hasPermission = await requestPermissions(useCamera ? 'camera' : 'gallery');
    if (!hasPermission) return;

    const result = useCamera 
      ? await ImagePicker.launchCameraAsync({
          allowsEditing: true,
          aspect: [1, 1],
          quality: 0.7,
        })
      : await ImagePicker.launchImageLibraryAsync({
          mediaTypes: ImagePicker.MediaTypeOptions.Images,
          allowsEditing: true,
          aspect: [1, 1],
          quality: 0.7,
        });

    if (!result.canceled) {
      setAvatarUri(result.assets[0].uri);
    }
  };

  const handleUpload = async () => {
    if (!avatarUri) {
      Alert.alert('Info', 'Veuillez sélectionner une photo');
      return;
    }
    setUploading(true);
    try {
      await onUpload(avatarUri);
      Alert.alert('Succès', 'Avatar mis à jour');
    } catch (error) {
      Alert.alert('Erreur', 'Échec de l\'upload. Vérifiez votre connexion.');
    } finally {
      setUploading(false);
    }
  };

  return (
    <View style={{ alignItems: 'center', padding: 20 }}>
      <TouchableOpacity onPress={() => Alert.alert('Changer avatar', 'Choisir une source', [
        { text: 'Appareil photo', onPress: () => pickImage(true) },
        { text: 'Galerie', onPress: () => pickImage(false) },
        { text: 'Annuler', style: 'cancel' }
      ])}>
        <Image
          source={{ uri: avatarUri || 'https://via.placeholder.com/120' }}
          style={{ width: 120, height: 120, borderRadius: 60, backgroundColor: '#ddd' }}
        />
      </TouchableOpacity>

      <Button 
        mode="contained" 
        onPress={handleUpload} 
        loading={uploading}
        disabled={uploading}
        style={{ marginTop: 15 }}
      >
        Enregistrer la photo
      </Button>
    </View>
  );
};

export default AvatarPicker;
