import React, { useState, useEffect } from 'react';
import { View, Text, Alert, Vibration, ActivityIndicator } from 'react-native';
import { BarCodeScanner } from 'expo-barcode-scanner';
import { useCartStore } from '../stores/cartStore';
import Toast from 'react-native-toast-message';

const BarcodeScannerScreen = ({ navigation }) => {
  const [hasPermission, setHasPermission] = useState(null);
  const [scanned, setScanned] = useState(false);
  const [loading, setLoading] = useState(false);
  const addToCart = useCartStore((state) => state.addItem);

  useEffect(() => {
    (async () => {
      const { status } = await BarCodeScanner.requestPermissionsAsync();
      setHasPermission(status === 'granted');
    })();
  }, []);

  const handleBarCodeScanned = async ({ type, data }) => {
    if (scanned || loading) return;
    setScanned(true);
    setLoading(true);
    Vibration.vibrate(200); // Feedback haptique

    try {
      // Appel API pour trouver le produit par code-barres
      const response = await fetch(`https://api.afrimarket.com/products/barcode/${data}`);

      if (response.status === 404) {
        Toast.show({
          type: 'error',
          text1: 'Produit non trouvé',
          text2: `Aucun produit avec le code ${data}`,
          position: 'bottom'
        });
        setScanned(false);
        return;
      }

      const product = await response.json();

      // Ajout au panier avec Zustand
      addToCart({ ...product, quantity: 1 });

      Toast.show({
        type: 'success',
        text1: 'Produit ajouté',
        text2: `${product.name} - ${product.price} FCFA`,
        position: 'bottom',
        onPress: () => navigation.navigate('Cart')
      });

      // Redirection après 1.5s
      setTimeout(() => {
        navigation.goBack();
      }, 1500);

    } catch (error) {
      Toast.show({
        type: 'error',
        text1: 'Erreur réseau',
        text2: 'Vérifiez votre connexion internet',
        position: 'bottom'
      });
      setScanned(false);
    } finally {
      setLoading(false);
    }
  };

  if (hasPermission === null) {
    return <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}><Text>Demande de permission...</Text></View>;
  }
  if (hasPermission === false) {
    return <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}><Text>Accès à la caméra refusé</Text></View>;
  }

  return (
    <View style={{ flex: 1 }}>
      <BarCodeScanner
        onBarCodeScanned={scanned ? undefined : handleBarCodeScanned}
        style={{ flex: 1 }}
        barCodeTypes={[BarCodeScanner.Constants.BarCodeType.ean13, BarCodeScanner.Constants.BarCodeType.qr]}
      />

      {/* Overlay d'instruction */}
      <View style={{ position: 'absolute', bottom: 50, left: 20, right: 20, backgroundColor: 'rgba(0,0,0,0.7)', padding: 15, borderRadius: 10 }}>
        <Text style={{ color: 'white', textAlign: 'center' }}>
          {loading ? 'Recherche du produit...' : 'Scannez le code-barres d\'un produit'}
        </Text>
        {loading && <ActivityIndicator color="white" style={{ marginTop: 10 }} />}
      </View>

      {scanned && !loading && (
        <View style={{ position: 'absolute', top: 50, alignSelf: 'center', backgroundColor: '#f0ad4e', padding: 8, borderRadius: 8 }}>
          <TouchableOpacity onPress={() => setScanned(false)}>
            <Text>Scanner à nouveau</Text>
          </TouchableOpacity>
        </View>
      )}
    </View>
  );
};

export default BarcodeScannerScreen;
```
